// --------------------------------------------------------
// 1. EXTRACT AI RESPONSE
// --------------------------------------------------------
const item = $input.first();
const json = item.json;

let aiOutput = json.candidates?.[0]?.content?.parts?.[0]?.text || json.text || json.response;

if (!aiOutput) {
  throw new Error('Could not find text in AI response. Check input structure.');
}

// --------------------------------------------------------
// 2. CLEAN & PARSE JSON
// --------------------------------------------------------
if (aiOutput.includes('```')) {
  aiOutput = aiOutput.split('```')[1];
  aiOutput = aiOutput.replace(/^json\s*/i, '');
}

let receiptData = {};
try {
  receiptData = JSON.parse(aiOutput.trim());
} catch (e) {
  receiptData = {
    summary: aiOutput,
    vendor: 'Parse Error',
    amount: 0,
    currency: 'INR',
    category: 'Miscellaneous'
  };
}

// --------------------------------------------------------
// 3. BUILD FILENAME
// --------------------------------------------------------
const binaryData = $('Get File').first().binary;
const binaryKey = Object.keys(binaryData)[0];
const fileExtension = binaryData[binaryKey].fileExtension || 'jpg';

const date = receiptData.date || new Date().toISOString().split('T')[0];
const safeVendor = (receiptData.vendor || 'Unknown').replace(/[^a-zA-Z0-9]/g, '');
const amount = receiptData.amount || 0;
const currency = (receiptData.currency || 'INR').toUpperCase();
const newFileName = `${date}_${safeVendor}_${amount}_${currency}.${fileExtension}`;

// --------------------------------------------------------
// 4. RETURN DATA
// --------------------------------------------------------
return {
  json: {
    vendor: receiptData.vendor || 'Unknown',
    date: date,
    amount: parseFloat(amount),
    currency: currency,
    category: receiptData.category || 'Miscellaneous',
    summary: receiptData.summary || '',
    newFileName: newFileName
  },
  binary: binaryData
};

